def solve(grid):
    import numpy as np
    from scipy import ndimage

    grid = np.array(grid)
    H, W = grid.shape

    # Find gray column
    gray_col = None
    for c in range(W):
        if all(grid[r][c] == 5 for r in range(H)):
            gray_col = c
            break

    # Initialize output
    result = np.full_like(grid, 6)
    result[:, gray_col] = 5

    # Find connected components of 0s
    labeled, num = ndimage.label(grid == 0)

    for shape_id in range(1, num + 1):
        coords = np.argwhere(labeled == shape_id)
        rmin, cmin = coords.min(axis=0)
        rmax, cmax = coords.max(axis=0)

        # Shift right so bounding box right edge = gray_col - 1
        shift = (gray_col - 1) - int(cmax)

        # Place shifted shape
        for r, c in coords:
            result[int(r), int(c) + shift] = 0

        # Check for red rows
        for r in range(int(rmin), int(rmax) + 1):
            row_zeros = sorted([int(c) + shift for rr, c in coords if rr == r])
            if not row_zeros:
                continue
            if row_zeros[-1] != gray_col - 1:
                continue
            # Check for holes between leftmost and rightmost 0
            has_hole = False
            for c in range(row_zeros[0], row_zeros[-1] + 1):
                if c not in row_zeros:
                    has_hole = True
                    break
            if has_hole:
                for c in range(gray_col + 1, W):
                    result[r, c] = 2

    return result.tolist()

